%%%%%%%%%% Function fBinImgOpnV01.m %%%%%%%%%%% Kei Nakamura% Created on Tuesday, May 30th 2007.% function img = fBinImgOpnV01(name);% loads and returns image data (binary, probably double). % img: output image data% name: name (could include path) for file% nRow: number of Row for an imagefunction img = fBinImgOpnV01(name,nRow)  %function headerfid = fopen(name,'r');  % open fileimg = fread(fid,[nRow, inf],'uint16');fclose(fid);
